// src/review.ts
var SYSTEM_PROMPT = `Voc\xEA \xE9 um revisor de c\xF3digo s\xEAnior. Analise o diff de um Pull Request e escreva um coment\xE1rio de review em markdown:
- resumo curto do que o PR faz
- at\xE9 5 pontos de aten\xE7\xE3o (bugs, riscos, c\xF3digo pouco claro) \u2014 s\xF3 se existirem, n\xE3o invente problemas
- n\xE3o repita o diff, seja direto`;
function formatDiff(files) {
  return files.map((file2) => `### ${file2.filename} (${file2.status}, +${file2.additions}/-${file2.deletions})
${file2.patch ?? "(sem patch dispon\xEDvel \u2014 bin\xE1rio ou arquivo grande)"}`).join("\n\n");
}
async function reviewDiff(files, apiKey, model) {
  const chatModel = model ?? new ChatOpenAI({
    apiKey,
    // ponytail: modelos free da OpenRouter mudam/saem do ar sem aviso — troque via OPENROUTER_MODEL se este parar de funcionar
    model: process.env.OPENROUTER_MODEL ?? "cohere/north-mini-code:free",
    temperature: 0.2,
    configuration: { baseURL: "https://openrouter.ai/api/v1" }
  });
  const response = await chatModel.invoke([
    { role: "system", content: SYSTEM_PROMPT },
    { role: "user", content: formatDiff(files) }
  ]);
  return response.content;
}

// src/index.ts
async function run() {
  const pullRequest = context2.payload.pull_request;
  if (!pullRequest) {
    setFailed("Este Action s\xF3 roda em eventos de pull_request.");
    return;
  }
  const token = getInput("github-token", { required: true });
  const openrouterApiKey = getInput("openrouter-api-key", { required: true });
  const octokit = getOctokit(token);
  const { owner, repo } = context2.repo;
  const files = await getPullRequestDiff(octokit, owner, repo, pullRequest.number);
  const review = await reviewDiff(files, openrouterApiKey);
  await postReviewComment(octokit, owner, repo, pullRequest.number, review);
  info(`Review postado no PR #${pullRequest.number}`);
}
run().catch((error52) => setFailed(error52 instanceof Error ? error52.message : String(error52)));
